cat > .pi-eval-route-blackbox.zig <<'EOF'
const std = @import("std");
const app = @import("src/main.zig");

fn segment(id: u32, kind: app.SegmentKind, meters: u32, seconds: u32, toll: u32, flags: u16) app.Segment {
    return .{ .id = id, .kind = kind, .meters = meters, .seconds = seconds, .toll_cents = toll, .flags = flags, .label = [_]u8{'x'} ** 32, .provenance = [_]u8{'y'} ** 64 };
}

test "route scoring black-box semantics" {
    const weights = [_]app.Weight{
        .{ .kind = .local, .distance_factor = 2, .time_factor = 5, .toll_factor = 0, .required_flags = 0b0001, .blocked_flags = 0b1000 },
        .{ .kind = .arterial, .distance_factor = 3, .time_factor = 4, .toll_factor = 1, .required_flags = 0, .blocked_flags = 0b0100 },
        .{ .kind = .highway, .distance_factor = 4, .time_factor = 2, .toll_factor = 3, .required_flags = 0b0010, .blocked_flags = 0 },
    };
    const segments = [_]app.Segment{
        segment(1, .local, 100, 10, 0, 0b0001),
        segment(2, .local, 100, 10, 0, 0),
        segment(3, .arterial, 50, 10, 20, 0),
        segment(4, .arterial, 50, 10, 20, 0b0100),
        segment(5, .highway, 80, 30, 10, 0b0010),
        segment(6, .ferry, 80, 30, 10, 0),
    };
    const score = try app.scoreSegments(std.testing.allocator, weights[0..], segments[0..]);
    try std.testing.expectEqual(@as(usize, 3), score.accepted);
    try std.testing.expectEqual(@as(usize, 3), score.rejected);
    try std.testing.expectEqual(@as(u64, 870), score.total);
    try std.testing.expect(score.checksum != 0);
}
EOF
zig test .pi-eval-route-blackbox.zig -OReleaseFast
